Bash(node -e "
const Database = require\('better-sqlite3'\);
const path = require\('path'\);
const crypto = require\('crypto'\);
const fs = require\('fs'\);
const db = new Database\(path.resolve\(process.env.DATABASE_URL || './data/intellidocs.db'\)\);

// Compute hash same way drizzle does \(sha256 of the SQL content\)
function hashFile\(filePath\) {
  const content = fs.readFileSync\(filePath, 'utf-8'\);
  return crypto.createHash\('sha256'\).update\(content\).digest\('hex'\);
}

const m1Hash = hashFile\('./drizzle/0001_unique_adam_destine.sql'\);
const m2Hash = hashFile\('./drizzle/0002_redundant_pet_avengers.sql'\);

db.prepare\('INSERT INTO __drizzle_migrations \(hash, created_at\) VALUES \(?, ?\)'\).run\(m1Hash, 1773428352118\);
db.prepare\('INSERT INTO __drizzle_migrations \(hash, created_at\) VALUES \(?, ?\)'\).run\(m2Hash, 1773511233834\);

console.log\('Inserted migration records'\);
const rows = db.prepare\('SELECT * FROM __drizzle_migrations'\).all\(\);
console.log\(JSON.stringify\(rows, null, 2\)\);
")

