Bash(node -e "
const { Editor } = require\('@tiptap/core'\);
const SK = require\('@tiptap/starter-kit'\);
const Collab = require\('@tiptap/extension-collaboration'\);
const CC = require\('@tiptap/extension-collaboration-cursor'\);
const Y = require\('yjs'\);
const { Awareness } = require\('y-protocols/awareness'\);

const doc = new Y.Doc\(\);
const awareness = new Awareness\(doc\);
awareness.setLocalStateField\('user', { name: 'test', color: '#000' }\);

// Create a mock provider with awareness
const mockProvider = { awareness, destroy: \(\) => {} };

try {
  const editor = new Editor\({
    extensions: [
      SK.default.configure\({ undoRedo: false }\),
      Collab.default.configure\({ document: doc, field: 'default' }\),
      CC.default.configure\({ provider: mockProvider, user: { name: 'test', color: '#000' } }\),
    ],
  }\);
  console.log\('Editor created successfully'\);
  console.log\('Doc content type:', editor.getJSON\(\)?.type\);
  editor.destroy\(\);
} catch \(e\) {
  console.log\('Error:', e.message\);
  console.log\('Stack:', e.stack?.split\('\\n'\).slice\(0,5\).join\('\\n'\)\);
}

doc.destroy\(\);
" 2>&1)

